      <!-- 省份标记点 -->
      <div v-for="r in regions" :key="r.id"
        class="map-dot"
        :class="{ hovered: hovered?.id === r.id }"
        :style="{ left: r.x + 'px', top: r.y + 'px' }"
        @mouseenter="onEnter(r, $event)"
        @mouseleave="onLeave"
      >
        <span class="map-dot-label">{{ r.name }}</span>
      </div>

      <!-- 悬浮提示框 -->
      <Teleport to="body">
        <Transition name="fade">
          <div v-if="hovered" class="map-tooltip" :style="tooltipStyle" @mouseenter="onTooltipEnter" @mouseleave="onLeave">
            <div class="tp-header">{{ hovered.name }}</div>
            <div class="tp-list">
              <div v-for="item in hovered.items" :key="item.name" class="tp-item">
                <span :class="item.inApp ? 'tp-inapp' : 'tp-other'">●</span>
                <span>{{ item.name }}</span>
                <span v-if="item.inApp" class="tp-badge">已有</span>
                <button v-else class="tp-vote" @click.stop="onVote(item.name)">
                  {{ voted === item.name ? '✓ 已记录' : '我感兴趣' }}
                </button>
                <span v-if="!item.inApp && voteCount(item.name) > 0" class="tp-count">{{ voteCount(item.name) }}人感兴趣</span>
              </div>
            </div>
          </div>
        </Transition>
      </Teleport>
    </div>

    <!-- 图例 -->
    <div class="map-legend">
      <span><span class="dot inapp"></span> 平台已有非遗课程</span>
      <span><span class="dot other"></span> 其他非遗项目</span>
    </div>

    <!-- 热门未收录 -->
    <div v-if="topVotes.length" class="top-votes">
      <p class="tv-title">🔥 最受期待的非遗项目</p>
      <div class="tv-list">
        <span v-for="(item, i) in topVotes" :key="i" class="tv-chip">
          {{ item.name }} <em>{{ item.count }}票</em>
        </span>
      </div>
    </div>
  </div>
</template>
